# Category: oidc_security

from flask import Flask, request, redirect, url_for
from flask_oidc import OpenIDConnect

app = Flask(__name__)
app.config["SECRET_KEY"] = "secret"
app.config["OIDC_CLIENT_SECRETS"] = "/path/to/client_secrets.json"
app.config["OIDC_REDIRECT_URI"] = url_for("authorized", _external=True)

oidc = OpenIDConnect(app)

@app.route("/")
def index():
    return "Welcome to the admin dashboard!"

@app.route("/login")
def login():
    return redirect(url_for("authorized", _external=True))

@app.route("/logout")
def logout():
    return redirect(url_for("index"))

@app.route("/authorized")
def authorized():
    if request.args.get("error"):
        return "Error: %s" % request.args.get("error")
    user = oidc.user_get()
    if not user:
        return redirect(url_for("login"))
    return "Welcome, %s!" % user["name"]